// Description: Java 25 Security Service Interface.
$MssSourceLicense$
package $reference ManufacturingSchema lower JavaPackage$.$reference ManufacturingSchema lower SchemaName$;
import server.markhome.mcf.v3_1.cflib.dbutil.CFLibDbKeyHash256;
/* * An I$SchemaName$SecurityService is the public service interface used by * normal applications to query the security server or a security server cache. * The I$SchemaName$SecurityControl interface is a private interface used by the * security server to control security server caches that have registered interest * in the security server. The control interface should never be accessed by * standard application logic, which does not perform the logins for the application, * delegating that responsibility to the security server and its forms and interfaces. */ public interface I$SchemaName$SecurityService {
/** * Get the SecurityControl interface for this controlled cache, if any. The final JPA layer has no control interface. * Note that this is not a general purpose public interface; it should only be used by the infrastructure code to control * and synchronize the caches in the system. Application logic should never use the control interface. * * @return The cache SecurityControl interface. */ public I$SchemaName$SecurityControl getSecurityControl();
/** * Probe the SecTent* security tables, then the SecClus* security tables, and finally the SecSys* tables * in order until a probe authorizes the users access to the permission group. There is no need to invoke * isMemberOfClusterGroup() or isMemberOfSystemGroup() if you invoke this method. * * @param userLogin The login id from the SecUser object for the user this query is for. * @param clusterId The cluster id of the cluster that contains the tenant being queried. * @param tenantId The tenant id being queried. * @param permissionName The name of the permission group being queried. * * @return true if the user is a member of the tenant group, the equivalent cluster admin group, or the equivalent system admin group, otherwise false. */ public boolean isMemberOfTenantGroup(String userLogin, CFLibDbKeyHash256 clusterId, CFLibDbKeyHash256 tenantId, String permissionName);
/** * Probe the SecTent* security tables, then the SecClus* security tables, and finally the SecSys* tables * in order until a probe authorizes the users access to the permission group. There is no need to invoke * isMemberOfClusterGroup() or isMemberOfSystemGroup() if you invoke this method. * * @param userId The user id for the SecUser object this query is for. * @param clusterId The cluster id of the cluster that contains the tenant being queried. * @param tenantId The tenant id being queried. * @param permissionName The name of the permission group being queried. * * @return true if the user is a member of the tenant group, the equivalent cluster admin group, or the equivalent system admin group, otherwise false. */ public boolean isMemberOfTenantGroup(CFLibDbKeyHash256 userId, CFLibDbKeyHash256 clusterId, CFLibDbKeyHash256 tenantId, String permissionName);
/** * Probe the SecClus* security tables, and then the SecSys* tables until a probe authorizes the users access * to the permission group as a cluster or system admin. There is no need to invoke isMemberOfSystemGroup() * if you invoke this method. * * @param userLogin The login id from the SecUser object for the user this query is for. * @param clusterId The cluster id being queried. * @param permissionName The name of the permission group being queried. * * @return true if the user is a member of the cluster group or the equivalent system admin group, otherwise false. */ public boolean isMemberOfClusterGroup(String userLogin, CFLibDbKeyHash256 clusterId, String permissionName);
/** * Probe the SecClus* security tables, and then the SecSys* tables until a probe authorizes the users access * to the permission group as a cluster or system admin. There is no need to invoke isMemberOfSystemGroup() * if you invoke this method. * * @param userId The user id for the SecUser object this query is for. * @param clusterId The cluster id being queried. * @param permissionName The name of the permission group being queried. * * @return true if the user is a member of the cluster group or the equivalent system admin group, otherwise false. */ public boolean isMemberOfClusterGroup(CFLibDbKeyHash256 userId, CFLibDbKeyHash256 clusterId, String permissionName);
/** * Probe the SecSys* tables for authorization of the users access to the permission group as a system admin. * * @param userLogin The login id from the SecUser object for the user this query is for * @param permissionName The name of the permission group being queried. * * @return true if the user is a member of the specified system group, otherwise false. */ public boolean isMemberOfSystemGroup(String userLogin, String permissionName);
/** * Probe the SecSys* tables for authorization of the users access to the permission group as a system admin. * * @param userId The user id for the SecUser object this query is for. * @param permissionName The name of the permission group being queried. * * @return true if the user is a member of the specified system group, otherwise false. */ public boolean isMemberOfSystemGroup(CFLibDbKeyHash256 userId, String permissionName); }
